hours = inputs.PCE_UNPAID_H.amount or 0.0 # Prefer regular worked hours line for month-hours; fallback to configured default month_hours = 0.0 try: lateness_code = payslip.env['ir.config_parameter'].sudo().get_param('pce.lateness_code', 'LAT') ot_codes = payslip.env['ir.config_parameter'].sudo().get_param('pce.ot_codes', 'OTW,OTR,PHO') ot_codes = [c.strip() for c in (ot_codes or '').split(',') if c.strip()] ignore = set(ot_codes + [lateness_code]) for l in payslip.worked_days_line_ids: if (l.code or '') and (l.code not in ignore): month_hours = max(month_hours, l.number_of_hours or 0.0) except Exception: month_hours = 0.0
if not month_hours: month_hours = float(payslip.env['ir.config_parameter'].sudo().get_param('pce.default_month_hours', '173.33') or 173.33)
hourly = (contract.wage or 0.0) / month_hours if month_hours else 0.0 # Salary rule amount must be positive; we use amount_negative to apply deduction result = hours * hourly
